operation.add:
        if(isset($oid)) {
        if ($this->config->get('payment_vindicartao_status')) {
        $nome = 'vindicartao';
        }

        if ($this->config->get('payment_vindiboleto_status')) {
        $nome = 'vindiboleto';
        }

        if ($this->config->get('payment_vindipix_status')) {
        $nome = 'vindipix';
        }

        $stat = $this->config->get('payment_' . $nome . '_order_status_id');

        $query = $this->db->query("SELECT * FROM " . DB_PREFIX . "order_history WHERE order_id = '" . (int)$oid . "' AND order_status_id = '" . (int)$stat . "' ORDER BY order_history_id DESC LIMIT 1");

        $data['text_message'] = nl2br($query->row['comment']);
        } else {
        $data['text_message'] = '';
        }

        if ($this->customer->isLogged()) {
			$data['text_message'] .= sprintf($this->language->get('text_customer'), $this->url->link('account/account', '', true), $this->url->link('account/order', '', true), $this->url->link('account/download', '', true), $this->url->link('information/contact'));
		} else {
			$data['text_message'] .= sprintf($this->language->get('text_guest'), $this->url->link('information/contact'));
		}

    $this->vindi = new VindiApi($this->registry);
    if($this->vindi->checkUpdate()) {
		    $data['update_vindi'] = 'Nova versão do módulo <b>Vindi</b> disponível para <a href="https://www.opencart.com/index.php?route=marketplace/extension/info&extension_id=48210" target="_blank">Download</a>!'; 
		} else {
		   $data['update_vindi'] = '';
		}

{% if update_vindi %}
<div class="alert alert-info"><i class="fa fa-exclamation-circle"></i> {{ update_vindi }}
  <button type="button" class="close" data-dismiss="alert">&times;</button>
</div>
{% endif %}
